import "core-js/modules/es.array.push.js";
export default {
  name: 'OSIPicta',
  props: {
    windowId: {
      type: String,
      required: true
    },
    USERID: {
      type: Number,
      default: 0
    }
  },
  data() {
    return {
      images: [],
      isLoading: false,
      currentIndex: -1,
      scale: 1,
      translateX: 0,
      translateY: 0,
      infoPanelVisible: false,
      currentImageInfo: {},
      canScrollLeft: false,
      canScrollRight: false,
      selectedThumbnailRef: null,
      saveTimeout: null,
      imageNaturalWidth: 0,
      imageNaturalHeight: 0,
      isZoomed: false,
      isDragging: false,
      dragStartX: 0,
      dragStartY: 0,
      dragStartTranslateX: 0,
      dragStartTranslateY: 0
    };
  },
  computed: {
    currentImage() {
      return this.images[this.currentIndex] || null;
    },
    imageStyle() {
      if (!this.currentImage) return {};
      const style = {
        opacity: this.isLoading ? 0.5 : 1,
        transition: this.isDragging ? 'none' : 'opacity 0.3s ease, transform 0.3s ease',
        maxWidth: this.isZoomed ? 'none' : '100%',
        maxHeight: this.isZoomed ? 'none' : '100%',
        width: this.isZoomed ? 'auto' : 'auto',
        height: this.isZoomed ? 'auto' : 'auto',
        cursor: this.isDragging ? 'grabbing' : this.isZoomed ? 'grab' : 'default',
        transform: `translate(${this.translateX}px, ${this.translateY}px) scale(${this.scale})`,
        transformOrigin: '0 0',
        willChange: 'transform'
      };
      return style;
    },
    // Вычисляем границы перетаскивания
    dragBounds() {
      if (!this.$refs.image || !this.$refs.viewport) {
        return {
          minX: 0,
          maxX: 0,
          minY: 0,
          maxY: 0
        };
      }
      const viewport = this.$refs.viewport;
      const img = this.$refs.image;
      const scaledWidth = img.naturalWidth * this.scale;
      const scaledHeight = img.naturalHeight * this.scale;
      const viewportWidth = viewport.clientWidth;
      const viewportHeight = viewport.clientHeight;

      // Вычисляем границы перемещения
      const minX = Math.min(0, viewportWidth - scaledWidth);
      const maxX = 0;
      const minY = Math.min(0, viewportHeight - scaledHeight);
      const maxY = 0;
      return {
        minX,
        maxX,
        minY,
        maxY
      };
    }
  },
  methods: {
    throttledSaveState() {
      if (this.saveTimeout) clearTimeout(this.saveTimeout);
      this.saveTimeout = setTimeout(() => {
        this.saveTimeout = null;
      }, 2000);
    },
    openFilePicker() {
      this.$refs.fileInput.click();
    },
    fileToDataUrl(file) {
      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = e => resolve(e.target.result);
        reader.onerror = e => reject(e);
        reader.readAsDataURL(file);
      });
    },
    async handleFileSelect(event) {
      const files = Array.from(event.target.files);
      await this.loadImages(files);
      event.target.value = '';
    },
    async loadImages(files) {
      this.isLoading = true;
      try {
        const newImages = [];
        for (const file of files) {
          const dataUrl = await this.fileToDataUrl(file);
          newImages.push({
            file,
            dataUrl,
            name: file.name,
            type: file.type,
            size: file.size,
            lastModified: file.lastModified
          });
        }
        this.images = [...this.images, ...newImages];
        if (this.images.length > 0 && this.currentIndex === -1) {
          this.currentIndex = 0;
          this.$nextTick(() => {
            this.onImageLoad();
          });
        }
      } catch (error) {
        console.error('Ошибка загрузки изображений:', error);
        alert('Не удалось загрузить изображения');
      } finally {
        this.isLoading = false;
      }
    },
    onImageLoad() {
      const img = this.$refs.image;
      if (img) {
        this.imageNaturalWidth = img.naturalWidth;
        this.imageNaturalHeight = img.naturalHeight;
      }
      this.Prepare_fileInfo();
      this.$nextTick(() => {
        this.scrollToSelectedThumbnail();
        this.fitToWindow();
        this.centerImage();
      });
    },
    fitToWindow() {
      if (!this.currentImage || !this.$refs.image || !this.$refs.viewport) return;
      const viewport = this.$refs.viewport;
      const img = this.$refs.image;
      if (img.complete) {
        const scaleX = viewport.clientWidth / img.naturalWidth;
        const scaleY = viewport.clientHeight / img.naturalHeight;

        // Если изображение меньше окна по обоим измерениям - показываем в оригинальном размере
        if (img.naturalWidth <= viewport.clientWidth && img.naturalHeight <= viewport.clientHeight) {
          this.scale = 1; // Оригинальный размер для маленьких картинок
        } else {
          // Для больших картинок - подгоняем под окно
          this.scale = Math.min(scaleX, scaleY, 1);
        }
        this.isZoomed = this.scale < 1; // Зум только если уменьшили
        this.centerImage();
        console.log('Fit to window:', this.scale);
        this.throttledSaveState();
      }
    },
    resetView() {
      // Сбрасываем масштаб и позицию
      this.scale = 1;
      this.translateX = 0;
      this.translateY = 0;
      this.isZoomed = false;

      // Подгоняем изображение под окно, если оно большое
      this.$nextTick(() => {
        this.fitToWindow();
      });
    },
    centerImage() {
      if (!this.$refs.image || !this.$refs.viewport) return;
      const viewport = this.$refs.viewport;
      const img = this.$refs.image;
      const scaledWidth = img.naturalWidth * this.scale;
      const scaledHeight = img.naturalHeight * this.scale;

      // Центрируем изображение
      this.translateX = Math.max(0, (viewport.clientWidth - scaledWidth) / 2);
      this.translateY = Math.max(0, (viewport.clientHeight - scaledHeight) / 2);
      console.log('Center image:', this.translateX, this.translateY);
    },
    zoomIn() {
      const oldScale = this.scale;
      this.scale = Math.min(this.scale * 1.2, 5);
      this.isZoomed = true;

      // Корректируем позицию, чтобы сохранить центр
      this.adjustPositionAfterZoom(oldScale);
      console.log('Zoom In:', this.scale);
    },
    zoomOut() {
      const oldScale = this.scale;
      this.scale = Math.max(this.scale * 0.8, 0.1);
      this.isZoomed = this.scale < 1;

      // Корректируем позицию, чтобы сохранить центр
      this.adjustPositionAfterZoom(oldScale);

      // Если вернулись к масштабу, который меньше или равен окну, центрируем
      if (!this.isZoomed) {
        this.centerImage();
      }
      console.log('Zoom Out:', this.scale);
    },
    adjustPositionAfterZoom(oldScale) {
      if (!this.$refs.viewport || !this.$refs.image) return;
      const viewport = this.$refs.viewport;
      const img = this.$refs.image;

      // Находим точку, которая была в центре
      const centerX = viewport.clientWidth / 2;
      const centerY = viewport.clientHeight / 2;

      // Находим координаты этой точки в исходном изображении
      const imgX = (centerX - this.translateX) / oldScale;
      const imgY = (centerY - this.translateY) / oldScale;

      // Вычисляем новые координаты translate, чтобы эта точка снова оказалась в центре
      let newTranslateX = centerX - imgX * this.scale;
      let newTranslateY = centerY - imgY * this.scale;

      // Применяем границы
      const bounds = this.dragBounds;
      newTranslateX = Math.max(bounds.minX, Math.min(bounds.maxX, newTranslateX));
      newTranslateY = Math.max(bounds.minY, Math.min(bounds.maxY, newTranslateY));
      this.translateX = newTranslateX;
      this.translateY = newTranslateY;
    },
    // Методы для перетаскивания
    onMouseDown(event) {
      if (!this.isZoomed || event.button !== 0) return; // Только при зуме и левая кнопка

      event.preventDefault();
      this.isDragging = true;
      this.dragStartX = event.clientX;
      this.dragStartY = event.clientY;
      this.dragStartTranslateX = this.translateX;
      this.dragStartTranslateY = this.translateY;
      window.addEventListener('mousemove', this.onMouseMove);
      window.addEventListener('mouseup', this.onMouseUp);
    },
    onMouseMove(event) {
      if (!this.isDragging) return;
      event.preventDefault();
      const deltaX = event.clientX - this.dragStartX;
      const deltaY = event.clientY - this.dragStartY;
      let newTranslateX = this.dragStartTranslateX + deltaX;
      let newTranslateY = this.dragStartTranslateY + deltaY;

      // Применяем границы
      const bounds = this.dragBounds;
      newTranslateX = Math.max(bounds.minX, Math.min(bounds.maxX, newTranslateX));
      newTranslateY = Math.max(bounds.minY, Math.min(bounds.maxY, newTranslateY));
      this.translateX = newTranslateX;
      this.translateY = newTranslateY;
    },
    onMouseUp() {
      if (this.isDragging) {
        this.isDragging = false;
        window.removeEventListener('mousemove', this.onMouseMove);
        window.removeEventListener('mouseup', this.onMouseUp);
      }
    },
    Chng_currentIndex(operVal) {
      let newVal = this.currentIndex;
      if (operVal === 'min' && this.currentIndex > 0) {
        newVal = this.currentIndex - 1;
      } else if (operVal === 'min') {
        newVal = 0;
      } else if (operVal === 'plus' && this.currentIndex < this.images.length - 1) {
        newVal = this.currentIndex + 1;
      } else if (operVal === 'plus') {
        newVal = this.images.length - 1;
      } else {
        newVal = this.currentIndex;
      }
      this.currentIndex = newVal;
      this.$nextTick(() => {
        this.scrollToSelectedThumbnail();
        this.Prepare_fileInfo();
        this.fitToWindow();
      });
    },
    onImageError() {
      alert('Не удалось загрузить изображение');
    },
    formatFileSize(bytes) {
      if (bytes === 0) return '0 Б';
      const k = 1024;
      const sizes = ['Б', 'КБ', 'МБ', 'ГБ'];
      const i = Math.floor(Math.log(bytes) / Math.log(k));
      return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
    },
    formatDate(timestamp) {
      return new Date(timestamp).toLocaleString();
    },
    MakeHandSelectImg(p) {
      let targetIndex = this.images.findIndex(elem => elem.dataUrl === p.dataUrl);
      if (targetIndex !== -1) {
        this.currentIndex = targetIndex;
        this.Prepare_fileInfo();
        this.$nextTick(() => {
          this.scrollToSelectedThumbnail();
          this.fitToWindow();
        });
      }
    },
    Prepare_fileInfo() {
      if (!this.currentImage) return;
      const img = this.$refs.image;
      this.currentImageInfo = {
        ...this.currentImage,
        width: img ? img.naturalWidth : 0,
        height: img ? img.naturalHeight : 0
      };
    },
    setSelectedThumbnailRef(el) {
      this.selectedThumbnailRef = el;
    },
    scrollToSelectedThumbnail() {
      if (this.selectedThumbnailRef && this.$refs.thumbnailList) {
        const container = this.$refs.thumbnailList;
        const thumbnail = this.selectedThumbnailRef;
        const containerWidth = container.clientWidth;
        const thumbnailLeft = thumbnail.offsetLeft;
        const thumbnailWidth = thumbnail.clientWidth;
        const scrollPosition = thumbnailLeft - containerWidth / 2 + thumbnailWidth / 2;
        container.scrollTo({
          left: scrollPosition,
          behavior: 'smooth'
        });
        this.updateScrollButtons();
      }
    },
    onThumbnailScroll() {
      this.updateScrollButtons();
    },
    updateScrollButtons() {
      if (this.$refs.thumbnailList) {
        const container = this.$refs.thumbnailList;
        this.canScrollLeft = container.scrollLeft > 0;
        this.canScrollRight = container.scrollLeft < container.scrollWidth - container.clientWidth - 5;
      }
    }
  },
  mounted() {
    window.addEventListener('resize', () => {
      this.fitToWindow();
      this.updateScrollButtons();
    });

    // Добавляем обработчики мыши для изображения
    this.$nextTick(() => {
      const img = this.$refs.image;
      if (img) {
        img.addEventListener('mousedown', this.onMouseDown);
      }
    });
  },
  beforeUnmount() {
    window.removeEventListener('resize', this.fitToWindow);
    window.removeEventListener('resize', this.updateScrollButtons);

    // Удаляем обработчики мыши
    const img = this.$refs.image;
    if (img) {
      img.removeEventListener('mousedown', this.onMouseDown);
    }
    window.removeEventListener('mousemove', this.onMouseMove);
    window.removeEventListener('mouseup', this.onMouseUp);
    if (this.saveTimeout) clearTimeout(this.saveTimeout);
  }
};
